class Solution:
    def maxAdjacentDistance(self, nums):
        n = len(nums)
        best = 0
        for i in range(n):
            for j in range(n):
                if (i + 1) % n == j or (j + 1) % n == i:
                    best = max(best, abs(nums[i] - nums[j]))
        return best

