var maxAdjacentDistance = function(nums) {
    const n = nums.length;
    let best = 0;
    for (let i = 0; i < n; i++) {
        const diff = Math.abs(nums[i] - nums[(i + 1) % n]);
        if (diff > best) best = diff;
    }
    return best;
};
